#include <iostream>
#include <sstream>
#include <string>
#include <vector>
#include <regex>

std::string mdToHtml(std::string &md) {
    std::vector<std::string> lines;
    std::stringstream ss(md);
    std::regex re_header;
    std::regex re_link;
    std::regex re_code;

    while (ss.good()) {
        std::string line;
        ss >> line;
        lines.push_back(line);
    }

    for (int i = 0; i < lines.size(); i++) {
        if (regex_match(lines[i], re_header)) {
            lines[i] = "<h1>" + lines[i].substr(lines[i].find_first_not_of("\n") + 1) + "</h1>";
        } else if (regex_match(lines[i], re_link)) {
            lines[i] = "<a href=\"" + std::string(lines[i].find_first_not_of("\""), lines[i].find_first_not_of("\"", lines[i].find_first_not_of("<", lines[i].find_first_not_of(">", 0) + 1)) + "\"") + "\">" + lines[i].substr(lines[i].find_first_not_of("\""), lines[i].find_first_not_of("\"", lines[i].find_first_not_of(">", lines[i].find_first_not_of(">", 0) + 1) + 1)) + "</a>";
        } else if (regex_match(lines[i], re_code)) {
            lines[i] = "<code>" + lines[i].substr(lines[i].find_first_not_of("\n") + 1) + "</code>";
        }
    }

    return std::string(lines.begin(), lines.end());
}

